SELECT oPerson."HASPERSONNAME" AS oPerson_hasPersonName FROM FIBEN."FINANCIALSERVICEACCOUNT" AS oFinancialServiceAccount INNER JOIN FIBEN."PERSON" AS oPerson ON oFinancialServiceAccount."ISOWNEDBY" = oPerson."PERSONID" WHERE NOT oPerson."HASPERSONNAME" IN (SELECT oInnerPerson."HASPERSONNAME" AS oInnerPerson_hasPersonName FROM FIBEN."SECURITIESTRANSACTION" AS oInnerSecuritiesTransaction INNER JOIN FIBEN."FINANCIALSERVICEACCOUNT" AS innerFinancialServiceAccount1 ON oInnerSecuritiesTransaction."ISFACILITATEDBY" = innerFinancialServiceAccount1."FINANCIALSERVICEACCOUNTID" INNER JOIN FIBEN."PERSON" AS oInnerPerson ON innerFinancialServiceAccount1."ISOWNEDBY" = oInnerPerson."PERSONID" INNER JOIN FIBEN."LISTEDSECURITY" AS oInnerListedSecurity ON oInnerSecuritiesTransaction."REFERSTO" = oInnerListedSecurity."LISTEDSECURITYID" WHERE oInnerSecuritiesTransaction."HASTYPE" = '1' AND oInnerListedSecurity."HASLEGALNAME" = 'Alphabet Inc.' AND oInnerSecuritiesTransaction."HASSETTLEMENTDATE" >= '2019-01-01 00:00:00.000' AND oInnerSecuritiesTransaction."HASSETTLEMENTDATE" <= '2019-12-31 23:59:00.000')
